    public EventCallback OnPlaceOrder { get; set; }
}
"}

{"path": "/tmp/sv-18015457450047e4a62fbfdf4aeb59e5/Components/CheckoutWizard.razor", "file_text": "<div class="checkout-wizard">
    @switch (currentStep)
    {
        case Step.Shipping:
            <ShippingStep Shipping="order.Shipping" OnNext="GoToPayment" />
            break;

        case Step.Payment:
            <PaymentStep Payment="order.Payment"
                         OnBack="GoToShipping"
                         OnPlaceOrder="HandlePlaceOrder" />
            break;
    }
</div>

@code {
    /// <summary>
    /// Raised when the user completes checkout, carrying the finished order.
    /// </summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }

    private Step currentStep = Step.Shipping;
    private readonly Order order = new();

    private void GoToPayment() => currentStep = Step.Payment;
    private void GoToShipping() => currentStep = Step.Shipping;

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}
"}

